<?php
namespace app\Services; use app\Repositories\MemberRepository; use app\Requests\Validator;
class MemberService{ private MemberRepository $repo; public function __construct(){ $this->repo=new MemberRepository(); } public function all($q=''){return $this->repo->all($q);} public function find($id){return $this->repo->find((int)$id);} public function save(array $d,?int $id=null):array{ $e=Validator::required($d,['member_code'=>'Mã thành viên','full_name'=>'Họ tên']); $e+=Validator::email($d,'email','Email'); if($e)return ['ok'=>false,'errors'=>$e]; $id?$this->repo->update($id,$d):$id=$this->repo->create($d); return ['ok'=>true,'data'=>$this->repo->find($id)]; } public function delete(int $id):array{ if($this->repo->unreturnedCount($id)>0)return ['ok'=>false,'message'=>'Không thể xóa vì thành viên đang có tài liệu chưa trả']; $this->repo->delete($id); return ['ok'=>true]; }}
